function solve(m: number, n: number, waitCost: number[][]): number {
    // Directions: right (0, 1), down (1, 0)
    const directions = [[0, 1], [1, 0]];

    // Initialize a 2D array to store the minimum cost to reach each cell at each time step
    // Since the time steps can be large, we use a priority queue (Dijkstra's algorithm)
    // We'll use a 2D array for the cost and a priority queue for Dijkstra's algorithm
    const dist = Array(m).fill(null).map(() => Array(n).fill(Infinity));
    dist[0][0] = 1; // Starting at (0, 0) with cost 1

    // Priority queue: [totalCost, time, i, j]
    const pq = [[1, 0, 0, 0]];

    while (pq.length > 0) {
        // Extract the cell with the minimum cost
        const [cost, time, i, j] = pq.shift() as [number, number, number, number];

        // If we've reached the destination, return the cost
        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        // If the current cost is higher than the recorded cost, skip
        if (cost > dist[i][j]) {
            continue;
        }

        // Determine if it's an odd or even time step
        const isOddTime = time % 2 === 1;

        if (isOddTime) {
            // Move to adjacent cell (right or down)
            for (const [dx, dy] of directions) {
                const ni = i + dx;
                const nj = j + dy;

                // Check if the new cell is within bounds
                if (ni >= 0 && ni < m && nj >= 0 && nj < n) {
                    // Calculate the cost to enter the new cell
                    const newCost = cost + (ni + 1) * (nj + 1);

                    // Update the distance array and priority queue
                    if (newCost < dist[ni][nj]) {
                        dist[ni][nj] = newCost;
                        pq.push([newCost, time + 1, ni, nj]);
                    }
                }
            }
        } else {
            // Wait in the current cell
            const waitCostValue = waitCost[i][j];
            const newCost = cost + waitCostValue;

            // Update the distance array and priority queue
            if (newCost < dist[i][j]) {
                dist[i][j] = newCost;
                pq.push([newCost, time + 1, i, j]);
            }
        }
    }

    // If we've exhausted all possibilities without reaching the destination
    return -1;
}

